const msg = $json.chatInput?.toLowerCase() || "";

let repeatFlag = false;

// detect repeated words
const words = msg.split(" ");
const seen = {};

for (let word of words) {
  seen[word] = (seen[word] || 0) + 1;
  if (seen[word] > 2) {
    repeatFlag = true;
    break;
  }
}

return [
  {
    json: {
      repeatFlag
    }
  }
];

const msg = $json.chatInput?.toLowerCase() || "";

let domainFlag = false;

// suspicious domains
const badDomains = [
  "bit.ly",
  "tinyurl",
  "grabify",
  ".xyz",
  ".top",
  ".click"
];

for (let domain of badDomains) {
  if (msg.includes(domain)) {
    domainFlag = true;
    break;
  }
}

return [
  {
    json: {
      domainFlag
    }
  }
];

const text = ($json.chatInput || "").toLowerCase();

let urgencyFlag = false;

if (
  text.includes("urgent") ||
  text.includes("immediately") ||
  text.includes("asap")
) {
  urgencyFlag = true;
}

return [
  {
    json: {
      urgencyFlag
    }
  }
];

const text = ($json.chatInput || "").toLowerCase();

// extract URL using regex
const urlMatch = text.match(/https?:\/\/[^\s]+/);

let linkFlag = false;
let suspicious = false;
let reasons = [];

if (urlMatch) {
  linkFlag = true;
  const url = urlMatch[0];

  // 🔍 Rule 1: check shorteners
  const shorteners = ["bit.ly", "tinyurl", "t.co", "goo.gl"];
  if (shorteners.some(domain => url.includes(domain))) {
    suspicious = true;
    reasons.push("Shortened URL detected");
  }

  // 🔍 Rule 2: check suspicious domains
  const badDomains = [".xyz", ".top", ".click", ".ru"];
  if (badDomains.some(domain => url.includes(domain))) {
    suspicious = true;
    reasons.push("Suspicious domain extension");
  }

  // 🔍 Rule 3: too many numbers
  const digitCount = (url.match(/\d/g) || []).length;
  if (digitCount > 5) {
    suspicious = true;
    reasons.push("Too many numbers in URL");
  }

  // 🔍 Rule 4: long URL
  if (url.length > 50) {
    suspicious = true;
    reasons.push("Unusually long URL");
  }

  // 🔍 Rule 5: fake keywords
  const fakeWords = ["login", "verify", "account", "secure", "update"];
  if (fakeWords.some(word => url.includes(word))) {
    suspicious = true;
    reasons.push("Contains phishing keywords");
  }
}

return [
  {
    json: {
      linkFlag,
      linkSuspicious: suspicious,
      linkReasons: reasons.length > 0 ? reasons : ["No suspicious patterns"]
    }
  }
];

