const msg = $json.chatInput?.toLowerCase() || "";

let spamFlag = false;

// Common spam keywords
const spamWords = [
  "free",
  "win",
  "winner",
  "prize",
  "offer",
  "click here",
  "claim",
  "reward",
  "gift",
  "limited offer"
];

for (let word of spamWords) {
  if (msg.includes(word)) {
    spamFlag = true;
    break;
  }
}

return [
  {
    json: {
      spamFlag
    }
  }
