let urgency = false;
let link = false;
let tone = false;
let spam = false;
let repeat = false;
let domain = false;
let linkSuspicious = false;
let linkReasons = [];

// collect flags
for (const item of items) {
  if (item.json.linkReasons !== undefined) linkReasons = item.json.linkReasons;
  if (item.json.urgencyFlag !== undefined) urgency = item.json.urgencyFlag;
  if (item.json.linkFlag !== undefined) link = item.json.linkFlag;
  if (item.json.linkSuspicious !== undefined) linkSuspicious = item.json.linkSuspicious;
  if (item.json.toneFlag !== undefined) tone = item.json.toneFlag;
  if (item.json.spamFlag !== undefined) spam = item.json.spamFlag;
  if (item.json.repeatFlag !== undefined) repeat = item.json.repeatFlag;
  if (item.json.domainFlag !== undefined) domain = item.json.domainFlag;
}

// scoring
let score = 0;
let reasons = [];

if (urgency) { score += 2; reasons.push("Urgency detected"); }
if (linkSuspicious) {score += 4; reasons.push("Suspicious link detected");
} else if (link) { score += 1; reasons.push("Link present"); }
if (tone) { score += 2; reasons.push("Emotional pressure"); }
if (spam) { score += 3; reasons.push("Spam keywords"); }
if (repeat) { score += 1; reasons.push("Repeated words"); }
if (domain) { score += 3; reasons.push("Suspicious domain"); }

// threat level
let threatLevel = "Safe";

if (score >= 7) {
  threatLevel = "🔴 High Risk";
} else if (score >= 3) {
  threatLevel = "🟡 Suspicious";
}

// 🔥 NEW: Threat type
let threatType = "Normal";

if (link && urgency) {
  threatType = "Phishing";
} else if (spam) {
  threatType = "Spam";
} else if (tone) {
  threatType = "Social Engineering";
}

// 🔥 NEW: Confidence
let confidence = Math.min(100, score * 12);

// 🔥 NEW: Action
let action = "No action needed";

if (threatLevel.includes("High Risk")) {
  action = "Block message + Alert user";
} else if (threatLevel.includes("Suspicious")) {
  action = "Warn user to be cautious";
}

return [
  {
    json: {
      threatLevel,
      threatType,
      score,
      confidence,
      reasons,
      action
    }
  }
];

const data = $json;

let reasonText = data.reasons.length > 0
  ? data.reasons.map(r => "• " + r).join(" | ")
  : "No issues detected";

let output =
  "🔐 Cyber Threat Analysis Report → " +
  data.threatLevel +
  " | Type: " + data.threatType +
  " | Score: " + data.score +
  " | Confidence: " + data.confidence + "%" +
  " | Reasons: " + reasonText +
  " | Action: " + data.action;

return [
  {
    json: {
      text: output
    }
  }
];
